	if encoded, err := json.Marshal(body); err == nil {
		_ = store.AppendEvent(beadID, bead.BeadEvent{
			Kind:      "bead-quality.lint",
			Summary:   summary,
			Body:      string(encoded),
			Actor:     actor,
			Source:    "ddx agent execute-loop",
			CreatedAt: createdAt,
		})
		return
	}
	parts := []string{
		fmt.Sprintf("score=%d", result.Score),
		"rationale=" + result.Rationale,
		fmt.Sprintf("suggested_fixes=%v", result.SuggestedFixes),
		fmt.Sprintf("waivers_applied=%v", result.WaiversApplied),
	}
	if threshold > 0 {
		parts = append(parts, fmt.Sprintf("threshold_score=%d", threshold))
	}
	if lintErr != nil {
		parts = append(parts, "warning="+lintErr.Error())
	}
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "bead-quality.lint",
		Summary:   summary,
		Body:      strings.Join(parts, "\n"),
		Actor:     actor,
		Source:    "ddx agent execute-loop",
		CreatedAt: createdAt,
	})
}

func executeBeadLoopEvent(report ExecuteBeadReport, actor string, createdAt time.Time) bead.BeadEvent {
	parts := []string{}
	if report.Status == ExecuteBeadStatusPreservedNeedsReview {
		parts = append(parts, preservedNeedsReviewNote(report))
	}
	if report.Detail != "" {
		parts = append(parts, report.Detail)
	}
	if report.Tier != "" {
		parts = append(parts, fmt.Sprintf("tier=%s", report.Tier))
	}
	if report.ProbeResult != "" {
		parts = append(parts, fmt.Sprintf("probe_result=%s", report.ProbeResult))
	}
	if report.NoChangesRationale != "" {
		parts = append(parts, fmt.Sprintf("rationale: %s", report.NoChangesRationale))
	}
	if report.ReviewRationale != "" {
		parts = append(parts, report.ReviewRationale)
	}
	if report.PreserveRef != "" {
		parts = append(parts, fmt.Sprintf("preserve_ref=%s", report.PreserveRef))
	}
	if report.ResultRev != "" {
		parts = append(parts, fmt.Sprintf("result_rev=%s", report.ResultRev))
	}
	if report.BaseRev != "" {
		parts = append(parts, fmt.Sprintf("base_rev=%s", report.BaseRev))
	}
	if report.RetryAfter != "" {
		parts = append(parts, fmt.Sprintf("retry_after=%s", report.RetryAfter))
	}
	if report.OutcomeReason != "" {
		parts = append(parts, fmt.Sprintf("outcome_reason=%s", report.OutcomeReason))
	}
	if report.PredictedPower > 0 {
		parts = append(parts, fmt.Sprintf("predicted_power=%d", report.PredictedPower))
	}
	if report.PredictedSpeedTPS > 0 {
		parts = append(parts, fmt.Sprintf("predicted_speed_tps=%.1f", report.PredictedSpeedTPS))
	}
	if report.PredictedCostUSDPer1kTokens > 0 {
		cost := fmt.Sprintf("predicted_cost_usd_per_1k_tokens=%.6f", report.PredictedCostUSDPer1kTokens)
		if report.PredictedCostSource != "" {
			cost += fmt.Sprintf(" source=%s", report.PredictedCostSource)
		}
		parts = append(parts, cost)
	} else if report.PredictedCostSource != "" {
		parts = append(parts, fmt.Sprintf("predicted_cost_source=%s", report.PredictedCostSource))
	}

	return bead.BeadEvent{
		Kind:      "execute-bead",
		Summary:   report.Status,
		Body:      strings.Join(parts, "\n"),
		Actor:     actor,
		Source:    "ddx agent execute-loop",
		CreatedAt: createdAt,
	}
}

func preservedNeedsReviewNote(report ExecuteBeadReport) string {
	parts := []string{
		"preserved-needs-review",
		"gate_summary=" + oneLineGateSummary(report.Detail),
	}
	if report.PreserveRef != "" {
		parts = append(parts, "preserve_ref="+report.PreserveRef)
	}
	if report.ResultRev != "" {
		parts = append(parts, "result_rev="+report.ResultRev)
	}
	return strings.Join(parts, "\n")
}

func oneLineGateSummary(detail string) string {
	detail = strings.TrimSpace(detail)
	if detail == "" {
		return "safety gate preserved result"
	}
	if idx := strings.IndexByte(detail, '\n'); idx >= 0 {
		detail = strings.TrimSpace(detail[:idx])
	}
	return detail
}

// writeLoopEvent emits one structured JSONL line to sink describing a
// milestone in an execute-bead loop run. Entries use the same envelope as
// the Fizeau harness (session_id/seq/type/ts/data) so existing log
// aggregators (FormatSessionLogLines, ddx server workers log) can parse
// the stream uniformly. Errors are swallowed: structured logging must
// never break the core execute-loop.
func writeLoopEvent(sink io.Writer, sessionID, eventType string, data map[string]any, ts time.Time) {
	if sink == nil {
		return
	}
	if data == nil {
		data = map[string]any{}
	}
	entry := map[string]any{
		"session_id": sessionID,
		"type":       eventType,
		"ts":         ts.UTC().Format(time.RFC3339Nano),
		"data":       data,
	}
	line, err := json.Marshal(entry)
	if err != nil {
		return
	}
	_, _ = sink.Write(line)
	_, _ = sink.Write([]byte("\n"))
}

// formatLoopResult returns a concise human-readable summary of a bead execution
// result using merged/preserved/error terminology instead of raw status codes.
func formatLoopResult(report ExecuteBeadReport) string {
	switch report.Status {
	case ExecuteBeadStatusSuccess:
		shortRev := report.ResultRev
		if len(shortRev) > 8 {
			shortRev = shortRev[:8]
		}
		if shortRev != "" {
			return fmt.Sprintf("merged (%s)", shortRev)
		}
		return "merged"
	case ExecuteBeadStatusAlreadySatisfied:
		return "already_satisfied"
	case ExecuteBeadStatusNoChanges:
		if report.NoChangesRationale != "" {
			return fmt.Sprintf("no_changes: %s", report.NoChangesRationale)
		}
		return "no_changes"
	default:
		detail := report.Detail
		if detail == "" {
			detail = report.Status
		}
		if report.PreserveRef != "" {
			return fmt.Sprintf("preserved: %s", detail)
		}
		return fmt.Sprintf("error: %s", detail)
	}
}

// addBeadLabel mutates the bead in place to add a label idempotently. The
// store handles persistence; concurrent callers serialize via the store lock.
func addBeadLabel(store ExecuteBeadLoopStore, beadID, label string) error {
	if label == "" {
		return nil
	}
	return store.Update(beadID, func(b *bead.Bead) {
		for _, existing := range b.Labels {
			if existing == label {
				return
			}
		}
		b.Labels = append(b.Labels, label)
	})
}

func shouldSuppressNoProgress(report ExecuteBeadReport) bool {
	if report.Disrupted {
		// ddx-5b3e57f4: a worker-disrupted attempt is not evidence the model
		// could not make progress. Skip the 6h no-progress cooldown so the
		// bead is immediately re-claimable by the next worker.
		return false
	}
	if isTransientOutcomeReason(report.OutcomeReason) {
		return false
	}
	if report.BaseRev == "" || report.ResultRev == "" {
		return false
	}
	return report.BaseRev == report.ResultRev
}

func isTransientOutcomeReason(reason string) bool {
	switch reason {
	case "transport", "quota", "routing", "timeout", "merge_conflict":
		return true
	default:
		return false
	}
}

// classifyDisruption examines the loop ctx and the executor's error to decide
// whether a failed ExecuteBead attempt was caused by external disruption
// (worker killed, context cancelled, transport error) rather than the model
// genuinely producing nothing. Returns ok=true plus a short reason kind when
// disruption is detected; the caller marks the report Disrupted to bypass the
// no-progress cooldown (ddx-5b3e57f4). Reason kinds are stable strings used
// in the disruption_detected event:
//
//	context_canceled, context_deadline, transport_error
func classifyDisruption(ctx context.Context, executorErr error) (string, bool) {
	if ctx != nil {
		switch ctx.Err() {
		case context.Canceled:
			return "context_canceled", true
		case context.DeadlineExceeded:
			return "context_deadline", true
		}
	}
	if executorErr == nil {
		return "", false
	}

// Package escalation implements a MinPower-only escalation ladder used by
// the execute-bead loop to pick the next power floor after a substantive
// failure. The ladder reasons about Power values only — it never inspects
// provider names, model IDs, harness names, or any other vendor-identifying
// attributes. This keeps escalation portable across catalogs that disagree
// on which vendor sits at which tier.
package escalation

import (
	"errors"
	"fmt"
	"sort"

	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// ErrLadderExhausted is returned by Ladder.Next when no power tier above
// the supplied actualPower exists in the catalog. Power escalation cannot
// proceed any further at this catalog.
var ErrLadderExhausted = errors.New("escalation: ladder exhausted; no higher power tier in catalog")

// NoViableProviderError signals that the next catalog tier above the
// caller's actualPower has no viable provider — i.e., every model at that
// tier is either unavailable or not auto-routable. The loop bumps further
// by calling Next(Floor) to skip past this dead tier.
type NoViableProviderError struct {
	// Floor is the catalog power tier that was skipped because it had no
	// viable provider. Pass this value back into Next() to bump further.
	Floor int
}

func (e *NoViableProviderError) Error() string {
	return fmt.Sprintf("escalation: no viable provider at floor %d", e.Floor)
}

// Ladder is a MinPower-only escalation ladder. It enumerates the distinct
// power tiers present in a model catalog, sorted ascending, and tracks
// which tiers have at least one viable model.
type Ladder struct {
	tiers     []int
	viableSet map[int]struct{}
}

// NewLadder constructs a Ladder from a model catalog. Models with Power<=0
// are ignored as unrated. A model contributes to the viable set when it is
// both Available and AutoRoutable; non-viable tiers remain present in the
// ladder so Next can report a typed NoViableProviderError when one is hit.
func NewLadder(models []agentlib.ModelInfo) *Ladder {
	seen := map[int]struct{}{}
	viable := map[int]struct{}{}
	for _, m := range models {
		if m.Power <= 0 {
			continue
		}
		seen[m.Power] = struct{}{}
		if m.Available && m.AutoRoutable {
			viable[m.Power] = struct{}{}
		}
	}
	tiers := make([]int, 0, len(seen))
	for p := range seen {
		tiers = append(tiers, p)
	}
	sort.Ints(tiers)
	return &Ladder{tiers: tiers, viableSet: viable}
}

// Tiers returns the distinct catalog power tiers, ascending. The returned
// slice is a copy.
func (l *Ladder) Tiers() []int {
	if l == nil {
		return nil
	}
	out := make([]int, len(l.tiers))
	copy(out, l.tiers)
	return out
}

// Next returns the next power floor strictly greater than actualPower.
//
// actualPower is sourced from the previous attempt's routing-actual record
// (RoutingActual.Power). The escalation loop calls Next(actualPower) after
// a substantive failure to obtain the floor for the next attempt.
//
// Three outcomes:
//
//   - The next catalog tier above actualPower has at least one viable
//     model: returns (floor, nil).
//   - The next catalog tier above actualPower has no viable provider:
//     returns (0, *NoViableProviderError{Floor: tier}). The loop bumps
//     further by calling Next(tier).
//   - No catalog tier above actualPower exists: returns (0, ErrLadderExhausted).
func (l *Ladder) Next(actualPower int) (int, error) {
	if l == nil || len(l.tiers) == 0 {
		return 0, ErrLadderExhausted
	}
	for _, t := range l.tiers {
		if t <= actualPower {
			continue
		}
		if _, ok := l.viableSet[t]; !ok {
			return 0, &NoViableProviderError{Floor: t}
		}
		return t, nil
	}
	return 0, ErrLadderExhausted
}

// has to join against the session index.
type costEventBody struct {
	AttemptID    string  `json:"attempt_id"`
	Harness      string  `json:"harness,omitempty"`
	Provider     string  `json:"provider,omitempty"`
	Model        string  `json:"model,omitempty"`
	InputTokens  int     `json:"input_tokens"`
	OutputTokens int     `json:"output_tokens"`
	TotalTokens  int     `json:"total_tokens"`
	CostUSD      float64 `json:"cost_usd"`
	DurationMS   int     `json:"duration_ms"`
	ExitCode     int     `json:"exit_code"`
}

// appendBeadCostEvidence records a kind:cost evidence entry on the bead with
// per-attempt token and dollar usage. Best-effort: errors are discarded so a
// store failure never aborts the main execute-bead flow. Emits nothing when
// the appender is nil, the beadID is empty, or every cost field is zero
// (e.g., dry-run, no-changes with no provider call).
func appendBeadCostEvidence(appender BeadEventAppender, beadID, attemptID string, body costEventBody) {
	if appender == nil || beadID == "" {
		return
	}
	if body.InputTokens == 0 && body.OutputTokens == 0 && body.TotalTokens == 0 && body.CostUSD == 0 {
		return
	}
	body.AttemptID = attemptID
	if body.TotalTokens == 0 {
		body.TotalTokens = body.InputTokens + body.OutputTokens
	}
	data, err := json.Marshal(body)
	if err != nil {
		return
	}
	var summary string
	if body.CostUSD > 0 {
		summary = fmt.Sprintf("tokens=%d cost_usd=%.4f", body.TotalTokens, body.CostUSD)
	} else {
		summary = fmt.Sprintf("tokens=%d", body.TotalTokens)
	}
	if body.Model != "" {
		summary += fmt.Sprintf(" model=%s", body.Model)
	}
	_ = appender.AppendEvent(beadID, bead.BeadEvent{
		Kind:    "cost",
		Summary: summary,
		Body:    string(data),
		Actor:   "ddx",
		Source:  "ddx agent execute-bead",
	})
}

// appendRateLimitRetryEvent records one rate-limit retry on the bead's
// event stream per TD-031 §4 / §8.4 RateLimitRetryContract. The event body
// carries the retry count and wait duration so an audit can reconstruct the
// pause without consulting routing logs.
func appendRateLimitRetryEvent(appender BeadEventAppender, beadID string, info RateLimitRetryInfo) {
	if appender == nil || beadID == "" {
		return
	}
	body := map[string]any{
		"attempt":     info.Attempt,
		"wait_ms":     info.Wait.Milliseconds(),
		"source":      info.Source,
		"elapsed_ms":  info.Elapsed.Milliseconds(),
		"over_budget": info.OverBudget,
	}
	if info.Result != nil {
		if info.Result.Harness != "" {
			body["harness"] = info.Result.Harness
		}
		if info.Result.Provider != "" {
			body["provider"] = info.Result.Provider
		}
		if info.Result.Model != "" {
			body["model"] = info.Result.Model
		}
	}
	data, err := json.Marshal(body)
	if err != nil {
		return
	}
	summary := fmt.Sprintf("attempt=%d wait=%s source=%s", info.Attempt, info.Wait.Round(time.Millisecond), info.Source)
	if info.OverBudget {
		summary = "budget exhausted: " + RateLimitBudgetExhaustedReason
	}
	_ = appender.AppendEvent(beadID, bead.BeadEvent{
		Kind:    RateLimitRetryEventKind,
		Summary: summary,
		Body:    string(data),
		Actor:   "ddx",
		Source:  "ddx agent execute-bead",
	})
}

// ExecuteBeadWithConfig is the thin worker: it creates an isolated worktree,
// constructs the agent prompt from bead context, runs the agent harness,
// synthesizes a commit if the agent left uncommitted changes, then cleans up
// the worktree and returns the result. It classifies outcomes as exactly one
// of:
//
//   - task_succeeded: agent exited 0 and produced one or more commits
//   - task_failed:    agent exited non-zero
//   - task_no_changes: agent exited 0, made no commits, and wrote a rationale
//   - task_no_evidence: agent exited 0 but made no commits and wrote no rationale
//
// Merge, UpdateRef, gate evaluation, preserve-ref management, and orphan
// recovery are the parent's responsibility (see LandBeadResult, RecoverOrphans).
//
// Agent dispatch: production callers leave runtime.Service and runtime.AgentRunner
// nil. ExecuteBeadWithConfig constructs a fresh agentlib.FizeauService from
// projectRoot via NewServiceFromWorkDir and dispatches via RunViaServiceWith.
// Tests may set runtime.AgentRunner to inject a fake that returns canned
// Result values; when set, it takes precedence over the service path.
func ExecuteBeadWithConfig(ctx context.Context, projectRoot string, beadID string, rcfg config.ResolvedConfig, runtime ExecuteBeadRuntime, gitOps GitOps) (*ExecuteBeadResult, error) {
	if ctx == nil {
		ctx = context.Background()
	}
	attemptID := GenerateAttemptID()
	if runtime.WorkerID == "" {
		runtime.WorkerID = os.Getenv("DDX_WORKER_ID")
	}

	wtPath := executeBeadWorktreePath(beadID, attemptID)
	if mkErr := os.MkdirAll(filepath.Dir(wtPath), 0o755); mkErr != nil {
		return nil, fmt.Errorf("creating execute-bead worktree parent dir: %w", mkErr)
	}

	// Commit beads.jsonl before spawning worktree so the worktree snapshot
	// includes any bead metadata updates (e.g. spec-id).
	if err := CommitTracker(projectRoot); err != nil {
		return nil, err
	}

	// Checkpoint any remaining caller dirt as a real commit on the current
	// branch (FEAT-012 §22, US-126 AC#1). The new HEAD becomes the effective
	// base for the worker worktree; caller's edits are preserved as a normal
	// commit they can `git reset HEAD~` if they want them back uncommitted.
	if _, err := gitOps.SynthesizeCommit(projectRoot, "chore: checkpoint pre-execute-bead "+attemptID); err != nil {
		return nil, fmt.Errorf("pre-execute-bead checkpoint: %w", err)
	}

	// Resolve base revision after the tracker + checkpoint commits.
	baseRev, err := resolveBase(gitOps, projectRoot, runtime.FromRev)
	if err != nil {
		return nil, err
	}

	// Create the isolated worktree. Orphan recovery is the parent's responsibility
	// (call RecoverOrphans before invoking workers).
	if err := gitOps.WorktreeAdd(projectRoot, wtPath, baseRev); err != nil {
		return nil, fmt.Errorf("creating isolated worktree: %w", err)
	}
	defer func() {
		_ = gitOps.WorktreeRemove(projectRoot, wtPath)
	}()

	// Publish the live run-state so operators and HELIX can observe what is
	// executing without polling the bead tracker (CONTRACT-001 §5). The file
	// is removed on completion; a crashed worker leaves a stale file that
	// RecoverOrphans sweeps before the next attempt.
	_ = WriteRunState(projectRoot, RunState{
		BeadID:       beadID,
		AttemptID:    attemptID,
		Harness:      rcfg.Harness(),
		Model:        rcfg.Model(),
		StartedAt:    time.Now().UTC(),
		WorktreePath: wtPath,
	})
	defer func() {
		_ = ClearRunState(projectRoot)
	}()

	// Repair project-local skill symlinks whose targets do not resolve inside
	// the freshly created worktree.
	_ = materializeWorktreeSkills(wtPath)

	// Prepare artifacts (context load, prompt generation).
	artifacts, err := prepareArtifacts(projectRoot, wtPath, beadID, attemptID, baseRev, rcfg, runtime)
	if err != nil {
		res := &ExecuteBeadResult{
			BeadID:    beadID,
			AttemptID: attemptID,
			WorkerID:  runtime.WorkerID,
			BaseRev:   baseRev,
			ResultRev: baseRev, // no commits; ResultRev == BaseRev signals no output
			ExitCode:  1,
			Error:     err.Error(),
			Outcome:   ExecuteBeadOutcomeTaskFailed,
		}
		if abInfo, _ := os.Stat(filepath.Join(projectRoot, ExecuteBeadArtifactDir, attemptID)); abInfo != nil && abInfo.IsDir() {
			res.ExecutionDir = filepath.Join(ExecuteBeadArtifactDir, attemptID)
		}
		res.FailureMode = ClassifyFailureMode(res.Outcome, res.ExitCode, res.Error)
		populateWorkerStatus(res)
		_ = writeArtifactJSON(filepath.Join(projectRoot, ExecuteBeadArtifactDir, attemptID, "result.json"), res)
		return res, fmt.Errorf("execute-bead context load: %w", err)
	}

	// Pre-create the execution bundle dir in the worktree so the agent can write
	// artifacts (e.g. no_changes_rationale.txt) without needing to create the
	// directory itself. Failures are non-fatal: the agent can create it on demand.
	_ = os.MkdirAll(filepath.Join(wtPath, artifacts.DirRel), 0o755)

	// Redirect per-run session/telemetry output into the DDx-owned execution
	// bundle so the embedded harness does not accumulate state at the worktree root.
	embeddedStateDir := filepath.Join(artifacts.DirAbs, "embedded")
	if err := os.MkdirAll(embeddedStateDir, 0o755); err != nil {
		return nil, fmt.Errorf("creating embedded state dir: %w", err)
	}

	sessionID := GenerateSessionID()
	startedAt := time.Now().UTC()

	runRuntime := AgentRunRuntime{
		PromptFile: artifacts.PromptAbs,
		WorkDir:    wtPath,
		Correlation: map[string]string{
			"bead_id":     beadID,
			"base_rev":    baseRev,
			"attempt_id":  attemptID,
			"session_id":  sessionID,
			"worker_id":   runtime.WorkerID,
			"bundle_path": artifacts.DirRel,
			"prompt_file": artifacts.PromptRel,
		},
		SessionLogDirOverride: embeddedStateDir,
		PermissionsOverride:   "unrestricted", // isolated worktree; writes must not require approval
		Role:                  "implementer",
		CorrelationID:         beadID + ":" + attemptID,
	}

	// Operator-cancel mid-attempt poll (ADR-022 §Cancel SLA). The poll
	// re-reads the bead's Extra every CancelPollInterval; on
	// cancel-requested:true it cancels the dispatch context (which kills the
	// agent subprocess at the next syscall boundary) and writes
	// cancel-honored:true so subsequent cancel POSTs are silent no-ops.
	dispatchCtx, dispatchCancel := context.WithCancel(ctx)
	defer dispatchCancel()
	cancelHonored := startCancelPoll(dispatchCtx, dispatchCancel, beadID, runtime.BeadCancel)

	agentResult, agentErr := dispatchAgentRun(dispatchCtx, projectRoot, runtime.Service, runtime.AgentRunner, rcfg, runRuntime)
	finishedAt := time.Now().UTC()

	exitCode := 0
	tokens := 0
	inputTokens := 0
	outputTokens := 0
	costUSD := 0.0
	resultModel := rcfg.Model()
	resultHarness := rcfg.Harness()
	resultProvider := ""
	actualPower := 0
	predictedPower := 0
	predictedSpeedTPS := 0.0
	predictedCostUSDPer1kTokens := 0.0
	predictedCostSource := ""
	agentErrMsg := ""
	agentStderr := ""
	if agentResult != nil {
		exitCode = agentResult.ExitCode
		tokens = agentResult.Tokens
		inputTokens = agentResult.InputTokens
		outputTokens = agentResult.OutputTokens
		costUSD = agentResult.CostUSD
		if agentResult.Error != "" {
			agentErrMsg = agentResult.Error
		}
		if agentResult.Stderr != "" {
			agentStderr = agentResult.Stderr
		}
		if agentResult.Model != "" {
			resultModel = agentResult.Model
		}
		if agentResult.Provider != "" {
			resultProvider = agentResult.Provider
		}
		if agentResult.Harness != "" {
			resultHarness = agentResult.Harness
		}
		if agentResult.ActualPower > 0 {
			actualPower = agentResult.ActualPower
		}
		predictedPower = agentResult.PredictedPower
		predictedSpeedTPS = agentResult.PredictedSpeedTPS
		predictedCostUSDPer1kTokens = agentResult.PredictedCostUSDPer1kTokens
		predictedCostSource = agentResult.PredictedCostSource
	}
	if agentErr != nil {
		if exitCode == 0 {
			exitCode = 1
		}
		agentErrMsg = agentErr.Error()
	}

	// Capture routing evidence from the agent result. These fields are
	// populated by RunAgent (embedded harness) and RunScript (script harness).
	routeReason := ""
	routeBaseURL := ""
	if agentResult != nil {
		routeReason = agentResult.RouteReason
		routeBaseURL = agentResult.ResolvedBaseURL
	}

	// Get the HEAD of the worktree after the agent ran.
	resultRev, revErr := gitOps.HeadRev(wtPath)
	if revErr != nil {
		res := &ExecuteBeadResult{
			BeadID:                      beadID,
			AttemptID:                   attemptID,
			WorkerID:                    runtime.WorkerID,
			BaseRev:                     baseRev,
			ResultRev:                   baseRev, // no commits readable; treat as no output
			Harness:                     resultHarness,
			Provider:                    resultProvider,
			Model:                       resultModel,
			ActualPower:                 actualPower,
			PredictedPower:              predictedPower,
			PredictedSpeedTPS:           predictedSpeedTPS,
			PredictedCostUSDPer1kTokens: predictedCostUSDPer1kTokens,
			PredictedCostSource:         predictedCostSource,
			SessionID:                   sessionID,
			DurationMS:                  int(finishedAt.Sub(startedAt).Milliseconds()),
			Tokens:                      tokens,
			CostUSD:                     costUSD,
			ExitCode:                    1,
			Error:                       agentErrMsg,
			Stderr:                      agentStderr,
			RateLimitBudget:             runtime.RateLimitMaxWait,
			Reason:                      revErr.Error(), // HeadRev failure; orchestrator prefers this over Error for Reason
			ExecutionDir:                artifacts.DirRel,
			PromptFile:                  artifacts.PromptRel,
			ManifestFile:                artifacts.ManifestRel,
			ResultFile:                  artifacts.ResultRel,
			StartedAt:                   startedAt,
			FinishedAt:                  finishedAt,
			Outcome:                     ExecuteBeadOutcomeTaskFailed,
		}
		res.FailureMode = ClassifyFailureMode(res.Outcome, res.ExitCode, res.Error)
		populateWorkerStatus(res)
		_ = writeArtifactJSON(artifacts.ResultAbs, res)
		return res, fmt.Errorf("failed to read worktree HEAD: %w", revErr)
	}

	// Write usage.json when the harness reports token usage or cost.
	// Done before SynthesizeCommit so usage data is available in the
	// preliminary result written for commit-message sourcing.
	var usageFileRel string
	if tokens > 0 || costUSD > 0 {
		usage := executeBeadUsage{
			AttemptID:    attemptID,
			Harness:      resultHarness,
			Provider:     resultProvider,
			Model:        resultModel,
			Tokens:       tokens,
			InputTokens:  inputTokens,
			OutputTokens: outputTokens,
			CostUSD:      costUSD,
		}
		if writeErr := writeArtifactJSON(artifacts.UsageAbs, usage); writeErr == nil {
			usageFileRel = artifacts.UsageRel
		}
	}

	// Synthesize a commit when the agent left tracked edits without committing.
	// Only do so for real changes — harness noise paths are excluded. If nothing
	// real was staged (committed is false), leave resultRev == baseRev so the
	// outcome is classified as task_no_changes.
	if resultRev == baseRev {
		if isDirty, _ := gitOps.IsDirty(wtPath); isDirty {
			// Build a preliminary result and write it to result.json before
			// calling SynthesizeCommit. The commit message is then sourced from
			// the tracked artifact file, satisfying the provenance contract:
			// "commit-message metadata must be projected from tracked artifact
			// files, never from ad hoc runtime state" (FEAT-006).
			// The final result.json is re-written after the commit with the
			// correct ResultRev, Outcome, and Status.
			prelimOutcome := ExecuteBeadOutcomeTaskSucceeded
			if exitCode != 0 {
				prelimOutcome = ExecuteBeadOutcomeTaskFailed
			}
			prelimRes := &ExecuteBeadResult{
				BeadID:                      beadID,
				AttemptID:                   attemptID,
				WorkerID:                    runtime.WorkerID,
				BaseRev:                     baseRev,
				ResultRev:                   "", // unknown until commit is made
				Harness:                     resultHarness,
				Provider:                    resultProvider,
				Model:                       resultModel,
				ActualPower:                 actualPower,
				PredictedPower:              predictedPower,
				PredictedSpeedTPS:           predictedSpeedTPS,
				PredictedCostUSDPer1kTokens: predictedCostUSDPer1kTokens,
				PredictedCostSource:         predictedCostSource,
				SessionID:                   sessionID,
				DurationMS:                  int(finishedAt.Sub(startedAt).Milliseconds()),
				Tokens:                      tokens,
				CostUSD:                     costUSD,
				ExitCode:                    exitCode,
				Error:                       agentErrMsg,
				Stderr:                      agentStderr,
				RateLimitBudget:             runtime.RateLimitMaxWait,
				ExecutionDir:                artifacts.DirRel,
				PromptFile:                  artifacts.PromptRel,
				ManifestFile:                artifacts.ManifestRel,
				ResultFile:                  artifacts.ResultRel,
				UsageFile:                   usageFileRel,
				StartedAt:                   startedAt,
				FinishedAt:                  finishedAt,
				Outcome:                     prelimOutcome,
			}
			populateWorkerStatus(prelimRes)
			_ = writeArtifactJSON(artifacts.ResultAbs, prelimRes)

			// Render the commit message from the tracked artifact file.
			commitMsg, msgErr := BuildCommitMessageFromResultFile(artifacts.ResultAbs)
			if msgErr != nil {
				commitMsg = "chore: execute-bead iteration " + beadID
			}

package agent

import (
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestZeroConfigRetryEscalationPolicy verifies the retry/escalation policy
// composes correctly when the loop starts from the new metadata-driven
// "profile=cheap by default" path (commit 3ddf3d52, ddx-b2c9a245). It is a
// follow-up to AC6 of ddx-b790449b: confirm that transient failures retry
// within the cheap tier (no escalation) and substantive failures escalate
// cheap -> standard -> smart.
//
// The test drives a simulated tier ladder using the real escalation
// primitives (InferTier, IsInfrastructureFailure, ShouldEscalate,
// TierToProfile, BuildEscalationSummary). It does not require a running
// agent service or harness binary.
func TestZeroConfigRetryEscalationPolicy(t *testing.T) {
	// 1. Unflagged bead: no tier label, no kind, short description.
	// InferTier must default to cheap so the loop starts at the cheap
	// tier instead of the previous always-cheap fallback or the SD-024
	// "no profile" path.
	b := &bead.Bead{
		ID:          "ddx-zero-config-001",
		Title:       "trivial cleanup, unflagged",
		Description: "minor doc tweak",
	}
	startTier := escalation.InferTier(b)
	require.Equal(t, escalation.TierCheap, startTier,
		"unflagged bead must infer cheap tier (zero-config default)")
	require.Equal(t, "cheap", escalation.TierToProfile(startTier),
		"cheap tier maps to 'cheap' profile string consumed by LoadAndResolve")

	// 2. Transient infrastructure failure on cheap tier (e.g. 502 from
	// the inference host). The policy is: do NOT escalate; defer with a
	// retry-after and try the same tier again. The model wasn't given
	// a fair chance, so escalation budget must not be consumed.
	transientStatus := ExecuteBeadStatusExecutionFailed
	transientDetail := "provider 502 Bad Gateway: connection refused"
	require.True(t,
		escalation.IsInfrastructureFailure(transientStatus, transientDetail),
		"502 Bad Gateway on execution_failed must be classified as infrastructure failure")
	require.True(t,
		escalation.ShouldEscalate(transientStatus),
		"execution_failed itself remains escalatable; the loop must consult IsInfrastructureFailure first to defer-vs-escalate")

	// Loop ordering invariant: when IsInfrastructureFailure is true the
	// loop body defers (retry-after) instead of advancing the tier. The
	// tier on the next attempt is therefore unchanged.
	tierAfterTransient := startTier
	require.Equal(t, escalation.TierCheap, tierAfterTransient,
		"transient failure must not advance the tier ladder")

	// 3. Substantive failure on cheap tier (e.g. tests failed). Policy:
	// escalate to the next tier (standard).
	substantiveStatus := ExecuteBeadStatusExecutionFailed
	substantiveDetail := "TestFoo failed: assertion mismatch"
	require.False(t,
		escalation.IsInfrastructureFailure(substantiveStatus, substantiveDetail),
		"a model-capability failure detail must not match infrastructure patterns")
	require.True(t,
		escalation.ShouldEscalate(substantiveStatus),
		"substantive execution_failed must escalate")
	tierAfterCheapSubstantive := nextTier(tierAfterTransient)
	require.Equal(t, escalation.TierStandard, tierAfterCheapSubstantive,
		"cheap -> standard escalation step")

	// 4. Substantive failure on standard tier. Policy: escalate to smart.
	standardStatus := ExecuteBeadStatusPostRunCheckFailed
	require.True(t,
		escalation.ShouldEscalate(standardStatus),
		"post_run_check_failed escalates")
	tierAfterStandardSubstantive := nextTier(tierAfterCheapSubstantive)
	require.Equal(t, escalation.TierSmart, tierAfterStandardSubstantive,
		"standard -> smart escalation step")

	// 5. Smart tier succeeds. Build the escalation summary and verify
	// the full trail is recorded with winning_tier=smart and the cheap
	// transient attempt counted as wasted-but-not-escalating-budget.
	attempts := []escalation.TierAttemptRecord{
		{Tier: string(escalation.TierCheap), Harness: "agent", Model: "cheap-model", Status: transientStatus, CostUSD: 0.0, DurationMS: 800},
		{Tier: string(escalation.TierCheap), Harness: "agent", Model: "cheap-model", Status: substantiveStatus, CostUSD: 0.02, DurationMS: 1500},
		{Tier: string(escalation.TierStandard), Harness: "codex", Model: "standard-model", Status: standardStatus, CostUSD: 0.15, DurationMS: 3400},
		{Tier: string(escalation.TierSmart), Harness: "claude", Model: "smart-model", Status: escalation.SuccessStatus, CostUSD: 0.80, DurationMS: 9000},
	}
	summary := escalation.BuildEscalationSummary(attempts, string(escalation.TierSmart))
	require.Equal(t, string(escalation.TierSmart), summary.WinningTier,
		"smart tier won the escalation")
	require.Len(t, summary.TiersAttempted, 4,
		"trail records all attempts including the deferred-transient cheap attempt")
	assert.InDelta(t, 0.97, summary.TotalCostUSD, 1e-9)
	assert.InDelta(t, 0.17, summary.WastedCostUSD, 1e-9,
		"cheap-substantive (0.02) + standard (0.15) wasted; cheap-transient billed $0; smart succeeded")
	assert.Equal(t, string(escalation.TierCheap), summary.TiersAttempted[0].Tier,
		"first attempt was cheap (the new metadata-driven default)")
	assert.Equal(t, string(escalation.TierSmart), summary.TiersAttempted[3].Tier,
		"final attempt was smart (top of ladder)")
}

// TestZeroConfigEscalationSummaryEventBody verifies the escalation summary
// is emitted as a kind:escalation-summary bead event when the cheap-default
// ladder runs to completion. This is the operator-visible artifact of the
// retry/escalation policy.
func TestZeroConfigEscalationSummaryEventBody(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())
	target := &bead.Bead{ID: "ddx-zero-config-002", Title: "cheap-default ladder", Priority: 0}
	require.NoError(t, store.Create(target))

	attempts := []escalation.TierAttemptRecord{
		{Tier: string(escalation.TierCheap), Status: ExecuteBeadStatusExecutionFailed, CostUSD: 0.01, DurationMS: 1000},
		{Tier: string(escalation.TierStandard), Status: ExecuteBeadStatusExecutionFailed, CostUSD: 0.10, DurationMS: 2000},
		{Tier: string(escalation.TierSmart), Status: escalation.SuccessStatus, CostUSD: 0.50, DurationMS: 4000},
	}
	require.NoError(t,
		escalation.AppendEscalationSummaryEvent(
			store, target.ID, "test-worker", attempts, string(escalation.TierSmart), time.Unix(1, 0).UTC()))

	events, err := store.Events(target.ID)
	require.NoError(t, err)
	var found *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "escalation-summary" {
			found = &events[i]
			break
		}
	}
	require.NotNil(t, found, "escalation-summary event must be appended for the cheap-default ladder run")
	assert.Contains(t, found.Summary, "winning_tier=smart")
	assert.Contains(t, found.Summary, "attempts=3")
	assert.Contains(t, found.Body, `"tier":"cheap"`,
		"summary body records cheap as the first-attempted tier (zero-config default)")
	assert.Contains(t, found.Body, `"tier":"standard"`)
	assert.Contains(t, found.Body, `"tier":"smart"`)
}

// nextTier advances one rung up the cheap -> standard -> smart ladder.
// Mirrors the implicit ladder used by the execute-loop when escalating
// beyond a substantive failure. Smart is the top; further calls stay
// at smart (callers exhaust escalation when ShouldEscalate fires at smart).
func nextTier(t escalation.ModelTier) escalation.ModelTier {
	switch t {
	case escalation.TierCheap:
		return escalation.TierStandard
	case escalation.TierStandard:
		return escalation.TierSmart
	default:
		return escalation.TierSmart
	}
}

